146	    element->value = malloc(value_len);
147	
148	    if (element->key && element->value) {
149	      memcpy(element->key, key, key_len);
150	      memcpy(element->value, value, value_len);
151	    } else {
152	      if (element->key) {
153	        free(element->key);
154	        //INFO("Cannot allocate memory for value");
155	      }
156	
157	      if (element->value) {
158	        free(element->value);
159	        //INFO("Cannot allocate memory for key");
160	      }
161	
162	      free(element);
163	      return -1; //No Memory
164	    }
165	  } else if (table->mode == MODE_VALUEREF) {
166	    //LOG("Adding a key-value pair to the hash table with hash -> %d, in VALUEREF MODE", (int)hash);
167	    element->key = malloc(key_len);
168	
169	    if (element->key) {
170	      memcpy(element->key, key, key_len);
171	    } else {
172	      //INFO("Cannot allocate memory for key");
173	      free(element);
174	      return -1; //No Memory
175	    }
176	
177	    element->value = value;
178	  } else if (table->mode == MODE_ALLREF) {
179	    //LOG("Adding a key-value pair to the hash table with hash -> %d, in ALLREF MODE", (int)hash);
180	    element->key = key;
181	    element->value = value;
182	  }
183	
184	  element->key_len = key_len;
185	  element->value_len = value_len;
186	  element->next = NULL;
187	
188	  // find the key position for chaining
189	  if (!table->store_house[hash]) {
190	    //LOG("No Conflicts adding the first element at %d", (int)hash);
191	    table->store_house[hash] = element;
192	    table->key_count++;
193	  } else {
194	    //LOG("Conflicts adding element at %d", (int)hash);
195	    hash_table_element_t *temp = table->store_house[hash];
196	
197	    while(temp->next) {
198	      while(temp->next && temp->next->key_len!=key_len) {
199	        temp = temp->next;
200	      }

      }

      if(temp->next) {
        if (!memcmp(temp->next->key, key, key_len)) {
          //LOG("Found Key at hash -> %d", (int)hash);
          hash_table_element_t *to_delete = temp->next;
          temp->next = element;
          element->next = to_delete->next;
          hash_table_element_delete(table, to_delete);
          // since we are replacing values no need to change key_count
          return 0;
        } else {
          temp = temp->next;
        }
      }
    }

    temp->next = element;
    table->key_count++;
  }

  return 0;
